package controller;
import koneksi.Koneksi;import model.Kelas;import util.UIUtils;import java.sql.*;import java.util.*;
public class KelasController{public List<Kelas> getAll()throws SQLException{List<Kelas>l=new ArrayList<>();try(PreparedStatement ps=Koneksi.getConnection().prepareStatement("SELECT * FROM kelas ORDER BY kode_kelas");ResultSet r=ps.executeQuery()){while(r.next())l.add(new Kelas(r.getInt(1),r.getString(2),r.getString(3)));}return l;}public boolean simpan(Kelas k)throws SQLException{String sql=k.getIdKelas()==0?"INSERT INTO kelas(kode_kelas,nama_kelas) VALUES(?,?)":"UPDATE kelas SET kode_kelas=?,nama_kelas=? WHERE id_kelas=?";try(PreparedStatement ps=Koneksi.getConnection().prepareStatement(sql)){ps.setString(1,k.getKodeKelas());ps.setString(2,k.getNamaKelas());if(k.getIdKelas()!=0)ps.setInt(3,k.getIdKelas());return ps.executeUpdate()>0;}}public boolean hapus(int id)throws SQLException{try(PreparedStatement ps=Koneksi.getConnection().prepareStatement("DELETE FROM kelas WHERE id_kelas=?")){ps.setInt(1,id);return ps.executeUpdate()>0;}}public List<UIUtils.Option> options()throws SQLException{List<UIUtils.Option>o=new ArrayList<>();for(Kelas k:getAll())o.add(new UIUtils.Option(k.getIdKelas(),k.getNamaKelas()));return o;}}
